def move(self, from_pos, to_pos):
        x_from, y_from = map(int, from_pos.split())
        x_to, y_to = map(int, to_pos.split())

        piece = self.board[x_from][y_from]
        if piece and piece.color == self.current_player:
            dx, dy = abs(x_to - x_from), abs(y_to - y_from)
            if (dx, dy) == (1, 1) or ((dx, dy) == (2, 2) and self.board[(x_from + x_to) // 2][(y_from + y_to) // 2] is not None):
                self.board[x_to][y_to] = piece
                self.board[x_from][y_from] = None

                # Check for capturing and continue moving if possible
                if dx == 2:
                    while True:
                        x_new, y_new = map(int, input("Capture another piece (yes/no): ").split())
                        if self.board[x_new][y_new].color == self.current_player:
                            break
                        dx_new, dy_new = abs(x_new - x_to), abs(y_new - y_to)
                        if (dx_new, dy_new) != (1, 1):
                            print("Invalid capture. Try again.")
                            continue

                        self.board[x_new][y_new] = None
                        self.board[(x_to + x_new) // 2][(y_to + y_new) // 2] = piece
                        x_to, y_to = x_new, y_new

                # Check for kinging
                if (self.current_player == 'white' and x_to == 0) or (self.current_player == 'black' and x_to == 7):
                    self.board[x_to][y_to].kinged = True

                return True
            else:
                print("Invalid move. Try again.")
        else:
            print("Invalid move. Try again.")

        return False
"""
